# Prefix caching with hash-based KV lookup
class PrefixCache:
    def __init__(self, max_entries=1024):
        self.cache = {}  # prefix_hash -> (KV_tensors, length)

    def compute_hash(self, input_ids, prefix_len):
        # ponytail: use xxhash for fast hashing
        return hash(tuple(input_ids[:prefix_len].tolist()))

    def lookup(self, input_ids, prefix_len):
        h = self.compute_hash(input_ids, prefix_len)
        if h in self.cache:
            return self.cache[h]
        return None

    def store(self, input_ids, prefix_len, kv_cache):
        h = self.compute_hash(input_ids, prefix_len)
        if len(self.cache) >= 1024:
            self.cache.pop(next(iter(self.cache)))  # LRU
        self.cache[h] = kv_cache
    # For optimal reuse, align prefix lengths across requests
